-- descriptions and helps
ZO_CreateStringId("MSAL_HELP_TITLE","|c999999AutoLoot+ est un gestionnaire de butin basé sur des |ceeeeeerègles personnalisées|c999999. Définissez ce qui doit rester dans votre sac et laissez l'addon gérer le reste avec les |ceeeeeDisposeurs|c999999 intégrés. Laisser, marquer comme déchet, déconstruire, détruire — tout est sous votre contrôle|r")
ZO_CreateStringId("MSAL_HELP_GEAR","|c999999Pour les |ceeeeeeéquipements de set collectés|c999999 filtrés par le Filtre d'Ensembles, l'addon utilisera les filtres suivants dans <<1>> pour déterminer s'il faut le piller.|r")
ZO_CreateStringId("MSAL_HELP_MATERIAL","|c999999Tous les matériaux seront ramassés automatiquement lorsque vous aurez |ceeeeee" .. GetString(SI_CROWN_STORE_MENU_ESO_PLUS_LABEL) .. "|c999999, quelle que soit la règle sur laquelle leurs filtres sont réglés, sauf si le matériau est volé|r")
ZO_CreateStringId("MSAL_HELP_MISC","|c999999Pour certains articles négociables de grande valeur, AutoLoot+ prend en charge la comparaison des prix via l'addon tiers (|ceeeeeeTTC, MM, ATT et TSC|c999999 pris en charge). \nLes fonctions liées à ces l'addon sont automatiquement ajoutées à ce menu lorsque vous les activez|r")
ZO_CreateStringId("MSAL_HELP_MISC_3RD_ENABLED","|c999999Pour certains articles négociables de grande valeur, AutoLoot+ prend en charge la comparaison des prix via l'addon tiers (|ceeeeeeTTC, MM, ATT et TSC|c999999 pris en charge). \nS’il référence un tiers, les objets non échangeables ou sans prix seront ramassés directement|r")
ZO_CreateStringId("MSAL_HELP_LIST","|c999999%s / %s offrent une flexibilité de règles avec la plus haute priorité. \nBlacklist : objets que l'addon ne doit jamais auto-looter (ex. équipement de set à vendre) ; Whitelist : objets à toujours ramasser. \n\nCollez un lien et appuyez sur Entrée pour ajouter ; menu déroulant pour retirer|r")
ZO_CreateStringId("MSAL_HELP_UNBOX","|c999999Déballe auto. les conteneurs, avec |ceeeeee<<1>>|c999999 appliqué aux objets filtrés.\nBoutons ci-dessous pour déballage manuel. Raccourcis (PC) et LibRadialMenu (console) supportés.|r")
ZO_CreateStringId("MSAL_HELP_UNWANTED","|c999999Le disposeur effectue les actions automatiques que vous avez définies pour les objets indésirables filtrés|r")
ZO_CreateStringId("MSAL_HELP_UNWANTED_CONSOLE","|c999999Le disposeur effectue les actions automatiques que vous avez définies pour les objets indésirables filtrés. \nVous pouvez utiliser la fonction |ceeeeee<<1>>|c999999 ici, avec un |ceeeeeeAuto-Sell|c999999 correspondant|r")
