ZO_CreateStringId("MSAL_AUTO_UNBOX","Auto-Unbox <<1>>")
ZO_CreateStringId("MSAL_UNBOX_CONTAINER_TOOLTIP","Lorsqu’il est activé, il ouvrira les conteneurs obtenus aussi rapidement que possible.\n\nSi l’objet acquis est un conteneur de récompenses quotidiennes d’artisanat et que vous utilisez |cdb8e0bLazy Writ Crafter|r ou |cdb8e0bSimpleDailyCraft|r, il se désactivera temporairement afin d’éviter tout conflit")
ZO_CreateStringId("MSAL_STOLEN_ITEMS_RULE","Règle sur les objets volés")
ZO_CreateStringId("MSAL_STOLEN_ITEMS_RULE_TOOLTIP","Avec |ccc922f<<1>>|r, l'addon ignore les objets volés dans la fenêtre de butin\n\nAvec |ccc922f<<2>>|r, l'addon empêche aussi le vol si vous êtes |ccc922fpas caché|r\n\nAvec |ccc922f<<3>>|r, l'addon suit vos paramètres pour les objets volés lorsque vous êtes |ccc922fcaché|r")
